import { create } from 'zustand';
import { authAPI, nguoiDungAPI } from '../services/api';

const useAuthStore = create((set, get) => ({
  user: null,
  token: localStorage.getItem('token'),
  loading: false,
  error: null,

  dangNhap: async (email, matKhau) => {
    set({ loading: true, error: null });
    try {
      const res = await authAPI.dangNhap({ email, matKhau });
      const { token, ...user } = res.data.data;
      localStorage.setItem('token', token);
      set({ token, user, loading: false });
      return true;
    } catch (err) {
      set({ error: err.response?.data?.message || 'Đăng nhập thất bại', loading: false });
      return false;
    }
  },

  dangKy: async (data) => {
    set({ loading: true, error: null });
    try {
      const res = await authAPI.dangKy(data);
      const { token, ...user } = res.data.data;
      localStorage.setItem('token', token);
      set({ token, user, loading: false });
      return true;
    } catch (err) {
      set({ error: err.response?.data?.message || 'Đăng ký thất bại', loading: false });
      return false;
    }
  },

  dangXuat: () => {
    localStorage.removeItem('token');
    set({ user: null, token: null });
  },

  layThongTinToi: async () => {
    if (!get().token) return;
    try {
      const res = await nguoiDungAPI.layThongTinToi();
      set({ user: res.data.data });
    } catch {}
  },

  clearError: () => set({ error: null }),
}));

export default useAuthStore;
